// CSD_RATIONALE_BEGIN
// This CSD strategy generates FOL formulas using the CSDHelpers library. It uses the parser
// to ensure the generated formulas are valid according to the FOL grammar rules. The strategy
// alternates between unconstrained and constrained steps, ensuring that the generated prefix
// remains a valid FOL statement throughout the process. Constrained steps are taken when the
// current prefix is not complete and can be extended without violating grammar rules.
// CSD_RATIONALE_END

generated := [];

while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  helpers.RollbackPreservesTokenInvariant(lm, parser, generated);

  if (stepsLeft > 1 || parser.IsCompletePrefix(generated))
  {
    var next, newSteps := helpers.UnconstrainedStep(lm, prompt, generated, stepsLeft);
  }
  else
  {
    var next, newSteps := helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft);
  }

  generated := generated + [next];
  stepsLeft := newSteps;
}

